  1→{% extends "base.html" %}
  2→
  3→{% block title %}Data - Maimai Assistant{% endblock %}
  4→
  5→{% block content %}
  6→<!-- Tabs -->
  7→<div class="tabs">
  8→    <button class="tab active" data-tab="candidates">Candidates</button>
  9→    <button class="tab" data-tab="messages">Messages</button>
 10→</div>
 11→
 12→<!-- Candidates Tab -->
 13→<div id="tab-candidates" class="tab-content active">
 14→    <div class="grid">
 15→        <input type="search" id="candidate-search" placeholder="Search by name, company, or title..." oninput="debouncedLoadCandidates()">
 16→        <button class="outline" onclick="exportCandidates()">Export Excel</button>
 17→    </div>
 18→
 19→    <table id="candidates-table">
 20→        <thead>
 21→            <tr>
 22→                <th>#</th>
 23→                <th>Name</th>
 24→                <th>Title</th>
 25→                <th>Company</th>
 26→                <th>Location</th>
 27→                <th>Messages</th>
 28→                <th>First Seen</th>
 29→            </tr>
 30→        </thead>
 31→        <tbody id="candidates-body">
 32→            <tr><td colspan="7">Loading...</td></tr>
 33→        </tbody>
 34→    </table>
 35→    <div id="candidates-pagination" class="pagination-controls"></div>
 36→</div>
 37→
 38→<!-- Messages Tab -->
 39→<div id="tab-messages" class="tab-content">
 40→    <table id="messages-table">
 41→        <thead>
 42→            <tr>
 43→                <th>#</th>
 44→                <th>Candidate</th>
 45→                <th>Template</th>
 46→                <th>Status</th>
 47→                <th>Content</th>
 48→                <th>Sent At</th>
 49→            </tr>
 50→        </thead>
 51→        <tbody id="messages-body">
 52→            <tr><td colspan="6">Loading...</td></tr>
 53→        </tbody>
 54→    </table>
 55→    <div id="msg-pagination" class="pagination-controls"></div>
 56→</div>
 57→{% endblock %}
 58→
 59→{% block scripts %}
 60→<script>
 61→// --- Tab switching ---
 62→document.querySelectorAll('.tabs .tab').forEach(btn => {
 63→    btn.addEventListener('click', () => {
 64→        document.querySelectorAll('.tabs .tab').forEach(t => t.classList.remove('active'));
 65→        document.querySelectorAll('.tab-content').forEach(c => c.classList.remove('active'));
 66→        btn.classList.add('active');
 67→        document.getElementById('tab-' + btn.dataset.tab).classList.add('active');
 68→    });
 69→});
 70→
 71→// --- Candidates ---
 72→let candidatePage = 1;
 73→const candidatePageSize = 20;
 74→
 75→async function loadCandidates(page = 1) {
 76→    candidatePage = page;
 77→    const search = document.getElementById('candidate-search').value.trim();
 78→    const params = new URLSearchParams({page, page_size: candidatePageSize});
 79→    if (search) params.append('search', search);
 80→
 81→    try {
 82→        const res = await fetch(`/api/candidates?${params}`);
 83→        if (!res.ok) throw new Error(`HTTP ${res.status}`);
 84→        const data = await res.json();
 85→        const tbody = document.getElementById('candidates-body');
 86→
 87→        if (!data.items.length) {
 88→            tbody.innerHTML = '<tr><td colspan="7">No candidates found</td></tr>';
 89→            document.getElementById('candidates-pagination').innerHTML = '';
 90→            return;
 91→        }
 92→
 93→        tbody.innerHTML = data.items.map((c, i) => `
 94→            <tr>
 95→                <td>${(page - 1) * candidatePageSize + i + 1}</td>
 96→                <td>${escapeHtml(c.name || '--')}</td>
 97→                <td>${escapeHtml(c.title || '--')}</td>
 98→                <td>${escapeHtml(c.company || '--')}</td>
 99→                <td>${escapeHtml(c.location || '--')}</td>
100→                <td>${c.message_count}</td>
101→                <td>${c.first_seen ? new Date(c.first_seen).toLocaleDateString() : '--'}</td>
102→            </tr>
103→        `).join('');
104→
105→        const pag = document.getElementById('candidates-pagination');
106→        let html = '';
107→        if (page > 1) html += `<button class="outline" onclick="loadCandidates(${page-1})">Previous</button> `;
108→        html += `<span>Page ${page} / ${data.total_pages} (${data.total} total)</span> `;
109→        if (page < data.total_pages) html += `<button class="outline" onclick="loadCandidates(${page+1})">Next</button>`;
110→        pag.innerHTML = html;
111→    } catch (e) {
112→        console.error('Failed to load candidates:', e);
113→    }
114→}
115→
116→let candidateDebounce;
117→function debouncedLoadCandidates() {
118→    clearTimeout(candidateDebounce);
119→    candidateDebounce = setTimeout(() => loadCandidates(1), 300);
120→}
121→
122→async function exportCandidates() {
123→    const search = document.getElementById('candidate-search').value.trim();
124→    const res = await fetch('/api/export', {
125→        method: 'POST',
126→        headers: {'Content-Type': 'application/json'},
127→        body: JSON.stringify({format: 'xlsx', search_keyword: search || null}),
128→    });
129→    const blob = await res.blob();
130→    const url = URL.createObjectURL(blob);
131→    const a = document.createElement('a');
132→    a.href = url;
133→    a.download = 'candidates.xlsx';
134→    a.click();
135→    URL.revokeObjectURL(url);
136→}
137→
138→// --- Messages ---
139→let msgPage = 1;
140→const msgPageSize = 20;
141→
142→async function loadMessages(page = 1) {
143→    msgPage = page;
144→    try {
145→        const msgRes = await fetch(`/api/messages?page=${page}&page_size=${msgPageSize}`);
146→        const tbody = document.getElementById('messages-body');
147→
148→        if (msgRes.ok) {
149→            const msgData = await msgRes.json();
150→            if (!msgData.items || !msgData.items.length) {
151→                tbody.innerHTML = '<tr><td colspan="6">No messages yet</td></tr>';
152→                document.getElementById('msg-pagination').innerHTML = '';
153→                return;
154→            }
155→            tbody.innerHTML = msgData.items.map((m, i) => `
156→                <tr>
157→                    <td>${(page-1) * msgPageSize + i + 1}</td>
158→                    <td>${escapeHtml(m.candidate_name || m.candidate_maimai_id)}</td>
159→                    <td>${escapeHtml(m.template_name || '--')}</td>
160→                    <td><span class="badge" data-status="${m.status}">${m.status}</span></td>
161→                    <td title="${escapeHtml(m.content)}">${escapeHtml(m.content.substring(0, 60))}${m.content.length > 60 ? '...' : ''}</td>
162→                    <td>${m.sent_at ? new Date(m.sent_at).toLocaleString() : '--'}</td>
163→                </tr>
164→            `).join('');
165→
166→            const pag = document.getElementById('msg-pagination');
167→            let html = '';
168→            if (page > 1) html += `<button class="outline" onclick="loadMessages(${page-1})">Previous</button> `;
169→            html += `<span>Page ${page} / ${msgData.total_pages} (${msgData.total} total)</span> `;
170→            if (page < msgData.total_pages) html += `<button class="outline" onclick="loadMessages(${page+1})">Next</button>`;
171→            pag.innerHTML = html;
172→        } else {
173→            tbody.innerHTML = '<tr><td colspan="6">Messages API not available</td></tr>';
174→        }
175→    } catch (e) {
176→        console.error('Failed to load messages:', e);
177→        document.getElementById('messages-body').innerHTML = '<tr><td colspan="6">Error loading messages</td></tr>';
178→    }
179→}
180→
181→// Init
182→loadCandidates();
183→loadMessages();
184→</script>
185→{% endblock %}
