  1→{% extends "base.html" %}
  2→
  3→{% block title %}Pipeline - Maimai Assistant{% endblock %}
  4→
  5→{% block content %}
  6→<!-- Status bar -->
  7→<div id="status-bar">
  8→    <div class="status-item">
  9→        <span class="dot" id="browser-dot"></span>
 10→        <span>Browser: <strong id="browser-status">--</strong></span>
 11→    </div>
 12→    <div class="status-item">
 13→        <span class="dot" id="login-dot"></span>
 14→        <span>Login: <strong id="login-status">--</strong></span>
 15→    </div>
 16→    <div class="status-item">
 17→        Queue: <strong id="queue-size">0</strong>
 18→    </div>
 19→</div>
 20→<div id="status-hint" hidden></div>
 21→
 22→<!-- Unified form -->
 23→<form id="pipeline-form">
 24→    <div class="grid">
 25→        <label>
 26→            Keywords (one per line)
 27→            <textarea name="keywords" rows="3" placeholder="e.g. 前端工程师" required></textarea>
 28→        </label>
 29→        <label>
 30→            Company filter (one per line, optional)
 31→            <textarea name="company" rows="3" placeholder="e.g. 字节跳动"></textarea>
 32→        </label>
 33→    </div>
 34→    <div class="grid">
 35→        <label>
 36→            Location (optional)
 37→            <input type="text" name="location" placeholder="e.g. 北京">
 38→        </label>
 39→        <label>
 40→            Template
 41→            <select name="template" id="template-select">
 42→                <option value="">-- Search only --</option>
 43→            </select>
 44→        </label>
 45→        <label>
 46→            Pages
 47→            <input type="number" name="pages" value="1" min="1" max="50">
 48→        </label>
 49→    </div>
 50→    <div id="template-vars"></div>
 51→    <fieldset id="messaging-options" hidden>
 52→        <label>
 53→            <input type="checkbox" name="auto_send">
 54→            Auto-send (skip candidate confirmation)
 55→        </label>
 56→    </fieldset>
 57→    <button type="submit" id="submit-btn">Search</button>
 58→</form>
 59→
 60→<!-- Progress section -->
 61→<div id="pipeline-progress" hidden>
 62→    <article>
 63→        <header>
 64→            <span id="pipeline-status-text">Queued...</span>
 65→            <span id="pipeline-task-id" class="badge" style="float:right"></span>
 66→        </header>
 67→        <progress id="pipeline-progress-bar" value="0" max="100"></progress>
 68→        <p id="pipeline-detail"></p>
 69→        <div id="pipeline-log"></div>
 70→    </article>
 71→</div>
 72→
 73→<!-- Confirmation section (manual mode) -->
 74→<div id="pipeline-confirm" hidden>
 75→    <article>
 76→        <header>Select Candidates to Message</header>
 77→        <p>
 78→            <label>
 79→                <input type="checkbox" id="select-all" onchange="toggleSelectAll(this.checked)">
 80→                Select All (<span id="confirm-count">0</span> candidates)
 81→            </label>
 82→        </p>
 83→        <div id="candidate-list"></div>
 84→        <footer>
 85→            <button onclick="confirmCandidates()" class="primary">Confirm & Send</button>
 86→            <button onclick="confirmCandidates(true)" class="secondary outline">Cancel</button>
 87→        </footer>
 88→    </article>
 89→</div>
 90→
 91→<!-- Search results (search-only mode) -->
 92→<div id="search-results" hidden>
 93→    <h3>Results (<span id="result-count">0</span> candidates)</h3>
 94→    <table>
 95→        <thead>
 96→            <tr>
 97→                <th>#</th>
 98→                <th>Name</th>
 99→                <th>Title</th>
100→                <th>Company</th>
101→                <th>Location</th>
102→            </tr>
103→        </thead>
104→        <tbody id="results-body"></tbody>
105→    </table>
106→    <button id="export-btn" class="outline" onclick="exportResults()">Export to Excel</button>
107→</div>
108→
109→<!-- Pipeline results -->
110→<div id="pipeline-results" hidden>
111→    <article>
112→        <header>Pipeline Complete</header>
113→        <div id="results-summary"></div>
114→    </article>
115→</div>
116→{% endblock %}
117→
118→{% block scripts %}
119→<script src="/static/js/pipeline.js"></script>
120→<script>
121→// --- Status bar auto-refresh ---
122→async function refreshStatus() {
123→    try {
124→        const [authRes, statusRes] = await Promise.all([
125→            fetch('/api/auth/status'),
126→            fetch('/api/status'),
127→        ]);
128→        const auth = await authRes.json();
129→        const status = await statusRes.json();
130→
131→        const bDot = document.getElementById('browser-dot');
132→        const lDot = document.getElementById('login-dot');
133→        document.getElementById('browser-status').textContent = auth.browser_connected ? 'Connected' : 'Disconnected';
134→        bDot.dataset.ok = auth.browser_connected;
135→        document.getElementById('login-status').textContent = auth.logged_in ? 'OK' : 'No';
136→        lDot.dataset.ok = auth.logged_in;
137→        document.getElementById('queue-size').textContent = status.queue.queue_size;
138→
139→        // Status hint
140→        const hint = document.getElementById('status-hint');
141→        if (!auth.browser_connected) {
142→            hint.hidden = false;
143→            hint.className = 'status-hint-err';
144→            hint.innerHTML = '<strong>Browser 未连接</strong> — 请先启动 Chrome 调试模式：<br>' +
145→                '<code>/Applications/Google\\ Chrome.app/Contents/MacOS/Google\\ Chrome --remote-debugging-port=9222 --user-data-dir=/tmp/chrome-debug-profile</code>';
146→        } else if (!auth.logged_in) {
147→            hint.hidden = false;
148→            hint.className = 'status-hint-warn';
149→            hint.innerHTML = '<strong>未登录脉脉</strong> — 请在已启动的 Chrome 中打开 <a href="https://maimai.cn" target="_blank">maimai.cn</a> 并手动登录，登录后此状态会自动刷新。';
150→        } else {
151→            hint.hidden = true;
152→        }
153→
154→        // Update connection badge in nav
155→        const badge = document.getElementById('connection-badge');
156→        if (auth.browser_connected && auth.logged_in) {
157→            badge.textContent = 'Online';
158→            badge.dataset.status = 'ok';
159→        } else if (auth.browser_connected) {
160→            badge.textContent = 'Not Logged In';
161→            badge.dataset.status = 'warn';
162→        } else {
163→            badge.textContent = 'Offline';
164→            badge.dataset.status = 'error';
165→        }
166→    } catch (e) {
167→        console.error('Status refresh failed:', e);
168→    }
169→}
170→refreshStatus();
171→setInterval(refreshStatus, 10000);
172→
173→// --- Template loading & mode switching ---
174→(async () => {
175→    try {
176→        const res = await fetch('/api/templates');
177→        if (!res.ok) throw new Error(`HTTP ${res.status}`);
178→        const templates = await res.json();
179→        const select = document.getElementById('template-select');
180→        // Append template options after the "Search only" default
181→        select.innerHTML = '<option value="">-- Search only --</option>';
182→        templates.forEach(t => {
183→            const opt = document.createElement('option');
184→            opt.value = t.name;
185→            opt.textContent = `${t.name} — ${t.description || 'No description'}`;
186→            select.appendChild(opt);
187→        });
188→
189→        function onTemplateChange() {
190→            const tpl = templates.find(t => t.name === select.value);
191→            const msgOpts = document.getElementById('messaging-options');
192→            const submitBtn = document.getElementById('submit-btn');
193→            const varsDiv = document.getElementById('template-vars');
194→
195→            if (select.value) {
196→                // Pipeline mode
197→                msgOpts.hidden = false;
198→                submitBtn.textContent = 'Start Pipeline';
199→                if (tpl && tpl.variables.length) {
200→                    const autoVars = ['name', 'company', 'position'];
201→                    const manualVars = tpl.variables.filter(v => !autoVars.includes(v));
202→                    if (manualVars.length) {
203→                        varsDiv.innerHTML = '<fieldset><legend>Template Variables</legend>' +
204→                            manualVars.map(v => {
205→                                const safe = escapeHtml(v);
206→                                return `<label>${safe}<input type="text" name="var_${safe}" placeholder="${safe}"></label>`;
207→                            }).join('') + '</fieldset>';
208→                    } else {
209→                        varsDiv.innerHTML = '<small>Variables (name, company, position) will be auto-filled per candidate.</small>';
210→                    }
211→                } else {
212→                    varsDiv.innerHTML = '';
213→                }
214→            } else {
215→                // Search-only mode
216→                msgOpts.hidden = true;
217→                submitBtn.textContent = 'Search';
218→                varsDiv.innerHTML = '';
219→            }
220→        }
221→
222→        select.addEventListener('change', onTemplateChange);
223→        onTemplateChange(); // init
224→    } catch (e) {
225→        console.error('Failed to load templates:', e);
226→    }
227→})();
228→</script>
229→{% endblock %}
