  1→/**
  2→ * WebSocket client with auto-reconnect for Maimai Assistant.
  3→ */
  4→
  5→class MaimaiWS {
  6→    constructor(path, options = {}) {
  7→        this.path = path;
  8→        this.options = options;
  9→        this.ws = null;
 10→        this.reconnectDelay = 1000;
 11→        this.maxReconnectDelay = 30000;
 12→        this.reconnectAttempts = 0;
 13→        this.maxReconnectAttempts = options.maxReconnect || 50;
 14→        this.closed = false;
 15→    }
 16→
 17→    connect() {
 18→        if (this.closed) return;
 19→
 20→        const protocol = location.protocol === 'https:' ? 'wss:' : 'ws:';
 21→        const url = `${protocol}//${location.host}${this.path}`;
 22→
 23→        this.ws = new WebSocket(url);
 24→
 25→        this.ws.onopen = () => {
 26→            this.reconnectAttempts = 0;
 27→            this.reconnectDelay = 1000;
 28→            if (this.options.onOpen) this.options.onOpen();
 29→            this._updateStatus('connected');
 30→        };
 31→
 32→        this.ws.onmessage = (event) => {
 33→            if (event.data === 'pong') return;
 34→
 35→            try {
 36→                const msg = JSON.parse(event.data);
 37→                if (msg.event === 'keepalive') return;
 38→                if (this.options.onMessage) this.options.onMessage(msg);
 39→            } catch (e) {
 40→                console.warn('WS parse error:', e);
 41→            }
 42→        };
 43→
 44→        this.ws.onclose = () => {
 45→            this._updateStatus('disconnected');
 46→            if (!this.closed) this._reconnect();
 47→        };
 48→
 49→        this.ws.onerror = (err) => {
 50→            console.error('WS error:', err);
 51→        };
 52→    }
 53→
 54→    send(data) {
 55→        if (this.ws && this.ws.readyState === WebSocket.OPEN) {
 56→            this.ws.send(typeof data === 'string' ? data : JSON.stringify(data));
 57→        }
 58→    }
 59→
 60→    close() {
 61→        this.closed = true;
 62→        if (this.ws) this.ws.close();
 63→    }
 64→
 65→    _reconnect() {
 66→        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
 67→            console.warn('WS max reconnect attempts reached');
 68→            return;
 69→        }
 70→
 71→        this.reconnectAttempts++;
 72→        const delay = Math.min(
 73→            this.reconnectDelay * Math.pow(1.5, this.reconnectAttempts - 1),
 74→            this.maxReconnectDelay
 75→        );
 76→
 77→        setTimeout(() => this.connect(), delay);
 78→    }
 79→
 80→    _updateStatus(status) {
 81→        const el = document.getElementById('ws-status');
 82→        if (el) {
 83→            el.textContent = `WebSocket: ${status}`;
 84→        }
 85→    }
 86→}
